import { useParams, useSearchParams } from "react-router-dom";
import { useState } from "react";
import { mockMovies, mockSeats } from "../../data/mockData";

import Seat from "../../components/Seat";
import SeatLegend from "../../components/SeatLegend";

import Banner from "../../components/Banner";
import "../styles/components_styles.css";
import "../styles/seat_booking.css";

const SeatBookingPage = () => {
  const { id } = useParams(); // movie ID
  const [searchParams] = useSearchParams();

  const [selectedSeats, setSelectedSeats] = useState<string[]>([]);

  const selectedDate = searchParams.get("date") ?? "";
  const selectedTime = searchParams.get("time") ?? "";
  const cinemaName = searchParams.get("cinema") ?? "";

  const movie = mockMovies.find((m) => m.id === Number(id));

  const showtime = mockSeats.find(
    (s) =>
      s.movieId === Number(id) &&
      s.cinema === cinemaName &&
      s.date === selectedDate &&
      s.time === selectedTime
  );

  const matchedSession = movie?.screenings
    ?.find((screening) => screening.cinema === cinemaName)
    ?.sessions?.find(
      (session) =>
        session.date === selectedDate && session.time === selectedTime
    );

  const roomName = matchedSession?.roomId ?? "Room Unknown";

  const handleToggle = (seatId: string) => {
    setSelectedSeats((prev) =>
      prev.includes(seatId)
        ? prev.filter((s) => s !== seatId)
        : [...prev, seatId]
    );
  };
  const SeatLegend = () => (
    <div className="seat-legend">
      <div className="legend-item">
        <img src="/icons/seat.svg" className="seat-icon available" />
        <span>Available</span>
      </div>
      <div className="legend-item">
        <img src="/icons/seat.svg" className="seat-icon selected" />
        <span>Selected</span>
      </div>
      <div className="legend-item">
        <img src="/icons/seat.svg" className="seat-icon sold" />
        <span>Sold</span>
      </div>
    </div>
  );

  if (!movie || !showtime) {
    return <div className="not-found">Showtime not found.</div>;
  }

  return (
    <>
      <Banner image={movie.banner}>
        {/* Header with logo and steps */}
        <div className="booking-header">
          <div className="logo-wrapper">
            <img src="/logo.svg" alt="Logo" className="booking-logo" />
          </div>
          <div className="booking-steps">
            <span className="step active">1. SELECT SEATS</span>
            <span className="step">2. CHECKOUT & PAYMENT</span>
          </div>
        </div>

        {/* Movie Info */}
        <div className="movie-info">
          <h1>{movie.title}</h1>
          <p>
            {movie.genre} | {movie.duration} | {movie.languages.join(", ")}
          </p>
          <p>
            {cinemaName} | {roomName} | {selectedDate} {selectedTime}
          </p>
        </div>

        {/* Showtimes (same cinema + room) */}
        <div className="showtime-tabs">
          {mockSeats
            .filter((s) => s.movieId === movie.id && s.cinema === cinemaName)
            .map((s, i) => (
              <button
                key={i}
                className={`showtime-btn ${
                  s.time === selectedTime ? "active" : ""
                }`}
                onClick={() =>
                  (window.location.href = `/booking/${movie.id}?cinema=${cinemaName}&date=${s.date}&time=${s.time}`)
                }
              >
                {s.time}
              </button>
            ))}
        </div>
      </Banner>

      {/* Main Seat Booking UI */}
      <div className="seat-booking-container">
        <div className="curved-screen">SCREEN</div>

        <SeatLegend />

        <div className="seat-grid">
          {showtime.seats.map((seat) => (
            <Seat
              key={seat.id}
              seat={seat}
              isSelected={selectedSeats.includes(seat.id)}
              onClick={() =>
                seat.status === "available" ? handleToggle(seat.id) : null
              }
            />
          ))}
        </div>

        <div className="bottom-bar">
          <div className="summary">
            <span>
              🎟️{" "}
              {selectedSeats.length
                ? `Selected: ${selectedSeats.join(", ")}`
                : "No seats selected"}
            </span>
            <button
              className="confirm-btn"
              disabled={!selectedSeats.length}
              onClick={() => alert("Booking Confirmed!")}
            >
              Book Now
            </button>
          </div>
        </div>
      </div>
    </>
  );
};

export default SeatBookingPage;
